  fixture: z.enum(['happy_path', 'idempotent_retry', 'downstream_failure', 'permission_denied']),
  action: z.enum(['start_flow', 'retry_same_request', 'simulate_failure', 'recover']),
  idempotencyKey: z.string().uuid(),
}).strict();

export const E2E211TrustedContextSchema = z.object({
  actorId: z.string().min(1),
  tenantId: z.string().min(1),
  role: z.enum(['owner','admin','member','viewer','system']),
  sessionId: z.string().min(1),
}).strict();

export const E2E211ResultSchema = z.object({
  status: z.enum(['passed','failed','denied','retryable_error']),
  httpStatus: z.union([z.literal(200), z.literal(202), z.literal(400), z.literal(403), z.literal(409), z.literal(422), z.literal(500)]),
  code: z.enum(['FLOW_COMPLETED', 'IDEMPOTENT_REPLAY', 'DOWNSTREAM_FAILED', 'PERMISSION_DENIED', 'RECOVERED']),
  userMessage: z.string().min(1),
  assertion: z.object({
    visibleState: z.literal('workflow_state_visible'),
    scenarioTitle: z.literal('Distributed lock for singleton job execution'),
    redactedTelemetry: z.object({ event: z.literal('e2e.e2e-211.checked'), category: z.literal('what_if_it_fails'), redacted: z.literal(true) }),
  }),
}).strict();

backend_solution:
// e2e-211: typed route for Distributed lock for singleton job execution
export async function handleE2E211(req, ctx) {
  const input = E2E211Schema.parse(await req.json());
  const authz = await ctx.authz.assertCan(input.actorId, 'what_if_it_fails', input.tenantId);
  const result = await ctx.db.transaction(tx => ctx.flows.distributed_lock_for_singleton_job(tx, input, authz));
  ctx.metrics.observe('error_rate', result.metric);
  return Response.json(ResultSchema.parse(result));
}

